class Solution {
    public int numberOfStableArrays(int zero, int one, int limit) {
        int MOD = (int)1e9 + 7;
        int N = zero + one;
        int[][] dp = new int[N + 1][N + 1];
        dp[0][0] = 1;
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= i; j++) {
                if (j > 0) dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % MOD;
                if (i - j > 0) dp[i][j] = (dp[i][j] + dp[i - 1][j]) % MOD;
            }
        }
        int res = 0;
        for (int i = Math.max(zero, one); i <= N; i++) {
            for (int j = Math.max(zero, one); j <= i; j++) {
                if (i - j > limit) continue;
                res = (res + dp[i][j]) % MOD;
            }
        }
        return res;
    }
}
